/**
 * Typed sample records — one per Giganto network raw-event type — used
 * by the parametrized descriptor test and the server-action dispatch
 * test.
 *
 * Each sample is annotated with its record interface, so `pnpm
 * typecheck` rejects any field whose value type drifts from `types.ts`
 * (e.g. a `StringNumber*` field given a JS number). The
 * `RAW_EVENT_SAMPLES` map then lets the test iterate all 20 types and
 * cross-check each fixture value against its descriptor scalar kind at
 * runtime.
 */

import type { RecordTypeId } from "@/lib/event/record-types";
